public class GCGenerations {

    // Short-lived: will be collected in minor GC
    static String processRequest(int id) {
        StringBuilder sb = new StringBuilder(); // dies after method returns
        for (int i = 0; i < 100; i++) sb.append(id).append(',';
        return sb.toString(); // String may survive if returned to caller
    }

    // Long-lived: promoted to old generation
    static final java.util.List<String> CACHE = new java.util.ArrayList<>();

    static void demonstrateGenerations() {
        // These StringBuilder objects are short-lived → collected in minor GC
        for (int i = 0; i < 1_000; i++) processRequest(i);

        // These Strings stay in old gen (referenced by CACHE)
        for (int i = 0; i < 10; i++) CACHE.add("persistent-" + i);

        System.out.println("Young gen mostly cleared, old gen holds CACHE");
    }

    // SoftReference: cleared only when JVM needs memory
    static java.lang.ref.SoftReference<byte[]> softCache;
    static void softRefDemo() {
        softCache = new java.lang.ref.SoftReference<>(new byte[1024 * 1024]); // 1MB
        byte[] data = softCache.get();
        System.out.println("SoftRef data: " + (data != null ? data.length + " bytes" : "GC'd"));
    }

    // WeakReference: collected on next GC regardless
    static void weakRefDemo() {
        Object obj = new Object();
        java.lang.ref.WeakReference<Object> weakRef = new java.lang.ref.WeakReference<>(obj);
        System.out.println("Before nulling: " + weakRef.get());
        obj = null; // remove strong reference
        System.gc(); // suggest GC (not guaranteed)
        System.out.println("After GC: " + weakRef.get()); // likely null
    }

    public static void main(String[] args) {
        demonstrateGenerations();
        softRefDemo();
        weakRefDemo();
    }
}

import java.util.*;

public class MemoryLeaks {

    // ── LEAK 1: Static collection grows unbounded ──────────────────
    static final Map<Integer, byte[]> STATIC_MAP = new HashMap<>();
    static void leak1_staticCollection(int id) {
        STATIC_MAP.put(id, new byte[1024]); // never removed → leak
    }

    // ── LEAK 2: Listener not removed ──────────────────────────────
    interface EventListener { void onEvent(String e); }
    static final List<EventListener> LISTENERS = new ArrayList<>();
    static class MyWidget {
        final EventListener listener;
        MyWidget() {
            this.listener = e -> System.out.println("Widget got: " + e);
            LISTENERS.add(this.listener); // REGISTERED
        }
        void destroy() {
            LISTENERS.remove(this.listener); // MUST deregister!
        }
    }

    // ── LEAK 3: ThreadLocal not cleaned ───────────────────────────
    static final ThreadLocal<List<String>> TL = ThreadLocal.withInitial(ArrayList::new);
    static void processInThread() {
        TL.get().add("data");
        // Must call TL.remove() after use in thread pools!
        // Thread pool reuses threads — ThreadLocal persists across tasks
        TL.remove(); // FIX
    }

    // ── FIX: Use WeakHashMap for automatic cleanup ─────────────────
    static final Map<Object, String> WEAK_MAP = new WeakHashMap<>();
    static void safeCache() {
        Object key = new Object();
        WEAK_MAP.put(key, "metadata");
        System.out.println("Size: " + WEAK_MAP.size()); // 1
        key = null;
        System.gc();
        System.out.println("After GC: " + WEAK_MAP.size()); // 0 (entry gone)
    }

    public static void main(String[] args) {
        // Don't call leak1 in a loop — it fills heap
        MyWidget w = new MyWidget();
        w.destroy(); // clean deregistration
        processInThread();
        safeCache();
    }
}

