import java.util.*;

public class Q1 {
    static final int MAX = 100;
    static final Map<String, byte[]> CACHE = new LinkedHashMap<>(MAX, 0.75f, true) {
        @Override protected boolean removeEldestEntry(Map.Entry<String, byte[]> eldest) {
            return size() > MAX;
        }
    };

    static void cacheRequest(String key, byte[] data) {
        CACHE.put(key, data);
    }

    public static void main(String[] args) {
        for (int i = 0; i < 200; i++) cacheRequest("key" + i, new byte[1024]);
        System.out.println("Cache size: " + CACHE.size()); // 100
    }
}

