import java.util.*;

public class Q3 {
    static final ThreadLocal<List<String>> TL = ThreadLocal.withInitial(ArrayList::new);

    static void runTask(String taskId) {
        try {
            TL.get().add(taskId);
            System.out.println(taskId + " log size: " + TL.get().size()); // always 1
        } finally {
            TL.remove(); // critical in thread pools
        }
    }

    public static void main(String[] args) {
        runTask("T1"); // T1 log size: 1
        runTask("T2"); // T2 log size: 1
    }
}
